		for _, action := range actionOrder {
			if len(resources[action]) > 0 {
				label := actionToLabel(action)
				count := len(resources[action])
				buf.WriteString(fmt.Sprintf("  %s: %d\n", label, count))
			}
		}
	}

	return buf.String()
}

// actionToLabel returns a human-readable label for an action.
func actionToLabel(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.CreateThenForget:
		return "Replace (create then forget)"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.NoOp:
		return "No-op"
	default:
		return "Unknown"
	}
}

// actionToSymbol returns a symbol representation for an action.
func actionToSymbol(action plans.Action) string {
	switch action {
	case plans.Create:
		return "+"
	case plans.Update:
		return "~"
	case plans.Delete:
		return "-"
	case plans.DeleteThenCreate:
		return "±"
	case plans.CreateThenDelete:
		return "∓"
	case plans.CreateThenForget:
		return "⨥"
	case plans.Read:
		return "<="
	case plans.Forget:
		return "."
	case plans.NoOp:
		return " "
	default:
		return "?"
	}
}

