		}
	}
}

func TestCompactDiffFormatter_Comprehensive(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	changes := plans.NewChangesSrc()

	// Create multiple resources with different actions
	resources := []struct {
		action plans.Action
		rtype  string
		name   string
	}{
		{plans.Create, "aws_instance", "web"},
		{plans.Create, "aws_instance", "app"},
		{plans.Update, "aws_security_group", "main"},
		{plans.Delete, "aws_instance", "old"},
		{plans.DeleteThenCreate, "aws_instance", "replaced"},
	}

	for _, res := range resources {
		addr := addrs.RootModuleInstance.ResourceInstance(
			addrs.ManagedResourceMode,
			res.rtype,
			res.name,
			addrs.NoKey,
		)
		changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
			Addr:        addr,
			PrevRunAddr: addr,
			ChangeSrc: plans.ChangeSrc{
				Action: res.action,
			},
		})
	}

	plan := &plans.Plan{
		Changes: changes,
	}
	schemas := &schemarepo.Schemas{}

	result := formatter.Format(plan, schemas)

	// Verify structure
	expectedItems := []string{
		"[+]",
		"[~]",
		"[-]",
		"[±]",
		"Summary:",
		"Create: 2",
		"Update: 1",
		"Delete: 1",
		"Replace (delete then create): 1",
	}

	for _, item := range expectedItems {
		if !strings.Contains(result, item) {
			t.Errorf("Expected %q in output, got:\n%s", item, result)
		}
	}

	// Verify all resource addresses are present
	expectedAddrs := []string{
		"aws_instance.web",
		"aws_instance.app",
		"aws_security_group.main",
		"aws_instance.old",
		"aws_instance.replaced",
	}

	for _, addr := range expectedAddrs {
		if !strings.Contains(result, addr) {
			t.Errorf("Expected resource address %q in output, got:\n%s", addr, result)
		}
	}
}

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := []struct {
		name           string
		plan           *plans.Plan
		schemas        *schemarepo.Schemas
		expectedOutput string
	}{
		{
			name:           "nil plan",
			plan:           nil,
			schemas:        &schemarepo.Schemas{},
			expectedOutput: "",
		},
		{
			name: "empty changes",
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			schemas:        &schemarepo.Schemas{},
			expectedOutput: "",
		},
	}

	formatter := &CompactDiffFormatter{}

	for _, test := range tests {
		t.Run(test.name, func(t *testing.T) {
			result := formatter.Format(test.plan, test.schemas)
			if !cmp.Equal(result, test.expectedOutput) {
				t.Errorf("unexpected output:\n%s", cmp.Diff(test.expectedOutput, result))
			}
		})
	}
}
